                            transition={{ duration: 0.5, delay: 0.3 }}
                        >
                            <button
                                onClick={onGetStarted}
                                className="premium-button-primary text-lg px-10 py-4"
                            >
                                Start Analysis Free
                            </button>
                            <button
                                onClick={() => window.scrollTo({ top: document.getElementById('features')?.offsetTop || 0, behavior: 'smooth' })}
