import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ChatbotProvider, useChatbot } from '../context/ChatbotContext';
import Chatbot from '../components/Chatbot/Chatbot';
import LimitedChat from '../components/Chatbot/LimitedChat';

// Main chat page component
function ChatPage() {
    const { authStatus, initializeChatbot } = useChatbot();
    const [isAuthChecking, setIsAuthChecking] = useState(true);
    const navigate = useNavigate();

    useEffect(() => {
        // Simulate auth checking delay
        const timer = setTimeout(() => {
            setIsAuthChecking(false);
        }, 1000);

        return () => clearTimeout(timer);
    }, []);

    useEffect(() => {
        // Re-initialize when auth status changes
        if (authStatus.isAuthenticated && initializeChatbot) {
            initializeChatbot();
        }
    }, [authStatus.isAuthenticated]);

    if (isAuthChecking) {
        return (
            <div className="chat-loading d-flex justify-content-center align-items-center" style={{ height: '100vh' }}>
                <div className="text-center">
                    <div className="spinner-border text-primary" role="status">
                        <span className="visually-hidden">Loading...</span>
                    </div>
                    <p className="mt-3 text-muted">Checking authentication status...</p>
                </div>
            </div>
        );
    }

    // Show LimitedChat for unauthenticated users
    if (!authStatus.isAuthenticated) {
        return (
            <LimitedChat
                onGetStarted={() => {
                    // Redirect to login page instead of using demo token
                    navigate('/login');
                }}
            />
        );
    }

    // Show full Chatbot for authenticated users
    return (
        <div className="chat-page h-100">
            <Chatbot userId={authStatus.userId} layout="split" />
        </div>
    );
}

// Wrapper component with provider
function ChatPageWithProvider() {
    return (
        <ChatbotProvider>
            <ChatPage />
        </ChatbotProvider>
    );
}

export default ChatPageWithProvider;

import React from 'react';
import { NavLink } from 'react-router-dom';
import {
    LayoutDashboard,
    FileText,
    Search,
    Settings,
    LogOut,
    MessageSquare,
    Zap,
    Share2,
    Database
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

const Sidebar = () => {
    const { logout, user } = useAuth();

    const navItems = [
        { icon: LayoutDashboard, label: 'Dashboard', path: '/dashboard' },
        { icon: FileText, label: 'Reports', path: '/reports' },
        { icon: MessageSquare, label: 'Chat', path: '/chat' },
        { icon: Search, label: 'Patent Search', path: '/search' },
        { icon: Share2, label: 'Graph Analysis', path: '/graph' },
        { icon: Zap, label: 'Prompts', path: '/prompts' },
        { icon: Settings, label: 'Settings', path: '/settings' },
    ];

    // Filter or add admin items based on user role
    const filteredNavItems = [...navItems];
    if (user?.role === 'admin') {
        filteredNavItems.push({ icon: Database, label: 'Admin', path: '/admin' });
    }

    return (
        <div className="w-64 bg-white border-r border-gray-200 h-screen flex flex-col z-10">
            <div className="h-16 flex items-center px-6 border-b border-gray-100">
                <div className="flex items-center gap-2">
                    <div className="w-8 h-8 bg-gradient-to-br from-blue-600 to-purple-600 rounded-lg flex items-center justify-center text-white font-bold text-lg shadow-md">
                        O
                    </div>
                    <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600">
                        Open Patent
                    </span>
                </div>
            </div>

            <nav className="flex-1 overflow-y-auto py-4">
                <ul className="space-y-1 px-3">
                    {filteredNavItems.map((item) => (
                        <li key={item.path}>
                            <NavLink
                                to={item.path}
                                className={({ isActive }) =>
                                    `flex items-center gap-3 px-3 py-2.5 rounded-lg transition-all duration-200 group ${isActive
                                        ? 'bg-blue-50 text-blue-600 shadow-sm font-medium'
                                        : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
                                    }`
                                }
                            >
                                <item.icon className="w-5 h-5 transition-transform group-hover:scale-110" />
                                <span>{item.label}</span>
                            </NavLink>
                        </li>
                    ))}
                </ul>
            </nav>

            <div className="p-4 border-t border-gray-100">
                <button
                    onClick={logout}
                    className="flex items-center gap-3 px-3 py-2.5 rounded-lg text-red-500 hover:bg-red-50 transition-colors w-full font-medium"
                >
                    <LogOut className="w-5 h-5" />
                    <span>Sign Out</span>
                </button>
            </div>
        </div>
    );
};

export default Sidebar;

